python3 -c "
import json, re

with open('/home/user/myproject/out/chart.html', 'r') as f:
    content = f.read()

# Find the embedded spec - it's typically in a JSON structure
# Look for the spec between script tags
scripts = re.findall(r'<script[^>]*>(.*?)</script>', content, re.DOTALL)
for i, script in enumerate(scripts):
    if 'spec' in script and 'layer' in script:
        # Find the JSON spec
        start = script.find('{')
        if start >= 0:
            # Find balanced braces
            depth = 0
            for j in range(start, len(script)):
                if script[j] == '{': depth += 1
                elif script[j] == '}': depth -= 1
                if depth == 0:
                    spec_str = script[start:j+1]
                    break
            spec = json.loads(spec_str)
            print('Found spec with keys:', list(spec.keys()))
            print()
            # Check layers
            if 'layer' in spec:
                for idx, layer in enumerate(spec['layer']):
                    print(f'Layer {idx}:')
                    if 'mark' in layer:
                        print(f'  mark: {layer[\"mark\"]}')
                    if 'encoding' in layer:
                        print(f'  encoding keys: {list(layer[\"encoding\"].keys())}')
                    if 'transform' in layer:
                        print(f'  transform: {json.dumps(layer[\"transform\"], indent=2)}')
            if 'params' in spec:
                print(f'params: {json.dumps(spec[\"params\"], indent=2)}')
            # Check for params in layers
            for idx, layer in enumerate(spec.get('layer', [])):
                if 'params' in layer:
                    print(f'Layer {idx} params: {json.dumps(layer[\"params\"], indent=2)[:1000]}')
            break
